employees = {}
dep1 = set()
dep2 = set()
while True:
    print('1.Add 2.Remove 3.Search 4.Display 5.Set Ops 6.Exit')
    ch = int(input('Choice: '))
    if ch == 1:
        eid = input('ID: ')
        name = input('Name: ')
        employees[eid] = name
    elif ch == 2:
        eid = input('ID: ')
        employees.pop(eid, None)
    elif ch == 3:
        eid = input('ID: ')
        print(employees.get(eid, 'Not Found'))
    elif ch == 4:
        for k in sorted(employees):
            print(k, employees[k])
    elif ch == 5:
        print('Union:', dep1 | dep2)
        print('Intersection:', dep1 & dep2)
        print('Difference:', dep1 - dep2)
    else:
        break
